import{_ as o,c as e,o as i,ae as t}from"./chunks/framework.CkyPvWOg.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"javascript/重排和重绘.md","filePath":"javascript/重排和重绘.md","lastUpdated":1773308029000}'),a={name:"javascript/重排和重绘.md"};function r(c,l,d,n,s,h){return i(),e("div",null,[...l[0]||(l[0]=[t('<h3 id="一-重排" tabindex="-1">一. 重排 <a class="header-anchor" href="#一-重排" aria-label="Permalink to &quot;一. 重排&quot;">​</a></h3><ul><li>浏览器重新计算页面<strong>元素布局</strong>，如(位置，尺寸，边距)的过程，之后也会进行重绘</li><li><strong>触发条件</strong>：</li></ul><ol><li>修改元素的<strong>几何</strong>属性(<code>width</code>,<code>height</code>,<code>margin</code>,<code>padding</code>)等；</li><li><code>添加</code>/<code>删除</code>dom元素；</li><li>修改<code>display</code>属性；</li><li>窗口大小变化或字体大小调整‌；</li><li>读取布局属性，如(<code>clientHeight</code>,<code>offsetWidth</code>)等会强制同步重排</li></ol><h3 id="性能影响" tabindex="-1">性能影响 <a class="header-anchor" href="#性能影响" aria-label="Permalink to &quot;性能影响&quot;">​</a></h3><ol><li>重排会触发完整的渲染流水线(布局→分层→绘制),开销较大‌</li><li>浏览器对<strong>修改操作‌</strong>采用<strong>异步重排</strong>（批量处理），但对<strong>读取操作</strong>‌会立即<strong>同步</strong>重排‌</li></ol><h3 id="二-重绘-repaint" tabindex="-1">二. 重绘（Repaint） <a class="header-anchor" href="#二-重绘-repaint" aria-label="Permalink to &quot;二.  重绘（Repaint）&quot;">​</a></h3><p>*重绘是浏览器重新绘制元素<strong>外观</strong>(如 颜色，背景，边框)的过程，不涉及布局计算</p><ul><li><strong>触发条件</strong>:</li></ul><ol><li>修改 <code>color</code>,<code>background-color</code>,<code>border</code>等非几何属性；</li><li>调整<code>opacity</code>或<code>visibility</code></li></ol><h3 id="‌性能影响‌" tabindex="-1">‌性能影响‌： <a class="header-anchor" href="#‌性能影响‌" aria-label="Permalink to &quot;‌性能影响‌：&quot;">​</a></h3><ol><li>重绘<strong>仅触发绘制阶段</strong>，性能开销比重排小‌</li><li>频繁重绘（如动画），仍可能导致页面卡顿‌</li></ol><h3 id="三-优化策略" tabindex="-1">三. 优化策略 <a class="header-anchor" href="#三-优化策略" aria-label="Permalink to &quot;三. 优化策略&quot;">​</a></h3><ol><li>减少重排:</li></ol><ul><li>批量修改DOM，使用documentFragment或class集中处理样式‌</li><li>避免频繁读取布局属性 (如 <code>getBoundingClientRect()</code>)</li></ul><ol start="2"><li>利用合成层:</li></ol><ul><li>使用<code>transform</code>、<code>opacity</code>等属性触发GPU加速，跳过重排/重绘‌</li><li>通过<code>will-change</code>: <code>transform</code>提前声明动画元素‌</li></ul><ol start="3"><li>控制动画频率</li></ol><ul><li>使用<code>requestAnimationFrame</code>同步屏幕刷新率‌</li><li>限制动画元素数量，优先处理关键动效‌</li></ul><h3 id="读取布局属性会触发强制同步重排" tabindex="-1">读取布局属性会触发强制同步重排 <a class="header-anchor" href="#读取布局属性会触发强制同步重排" aria-label="Permalink to &quot;读取布局属性会触发强制同步重排&quot;">​</a></h3><ul><li>主要触发重排的布局属性：</li></ul><ol><li>offset系列： offsetWidth，offsetHeight,offsetTop,offsetLeft</li><li>client系列: clientWidth,clientHeight,clientTop,clientLeft</li><li>scroll系列‌: scrollWidth,scrollHeight,scrollTop,scrollLeft</li><li>getComputedStyle()‌: 获取元素计算后的样式值</li><li>getBoundingClientRect()‌: 获取元素相对于视口的位置和尺寸信息</li></ol><h4 id="触发机制说明" tabindex="-1">触发机制说明 <a class="header-anchor" href="#触发机制说明" aria-label="Permalink to &quot;触发机制说明&quot;">​</a></h4><ul><li>当读取这些属性时，浏览器为了返回精确的布局信息，会强制清空当前的布局队列并<strong>立即进行重排计算</strong>.这种强制同步布局对性能影响较大，因为重排会重新计算元素的几何属性并重构渲染树</li></ul>',23)])])}const f=o(a,[["render",r]]);export{g as __pageData,f as default};
